diff --git a/packages/logger/src/__tests__/logger.test.js b/packages/logger/src/__tests__/logger.test.js
new file mode 100644
index 0000000..1acc3bd
--- /dev/null
+++ b/packages/logger/src/__tests__/logger.test.js
@@ -0,0 +1,79 @@
+import makeConsoleMock from 'consolemock';
+import { logger, getTimestamp } from '../';
+
+beforeAll(() => {
+  /* eslint-disable no-global-assign */
+  console = makeConsoleMock(console);
+});
+
+/* eslint-disable no-console */
+afterEach(() => {
+  console.clearHistory();
+});
+
+Date.now = jest.fn(() => 1489105897006);
+// toTimeString will return the time in the machine's timezone.
+// The following stub ensures that the tests will work from any
+// timezone. This is especially needed to make the tests pass on
+// circle-ci.
+/* eslint-disable no-extend-native */
+Date.prototype.toTimeString = jest.fn(() => '19:31:37 GMT-0500 (EST)');
+
+const makeAction = () => ({ type: 'ROUTE_CHANGED', payload: '/home' });
+
+it('1. logs actions and any resulting analytics event', () => {
+  const events = [{ hitType: 'pageview', page: '/home' }];
+  const action = makeAction();
+  logger(events, action);
+  expect(console.printHistory()).toMatchSnapshot();
+});
+
+it('2. logs actions and any resulting analytics events', () => {
+  const events = [
+    { hitType: 'pageview', page: '/' },
+    { hitType: 'pageview', page: '/home' },
+  ];
+  const action = makeAction();
+  logger(events, action);
+  expect(console.printHistory()).toMatchSnapshot();
+});
+
+it('3. logs events that are saved offline with a helpful message', () => {
+  const events = [{ hitType: 'pageview', page: '/' }];
+  const action = makeAction();
+  logger(events, action, {}, true);
+  expect(console.printHistory()).toMatchSnapshot();
+});
+
+it('4. logs events that were saved offline with a helpful message', () => {
+  const events = [{ hitType: 'pageview', page: '/' }];
+  logger(events, null, null, false, true);
+  expect(console.printHistory()).toMatchSnapshot();
+});
+
+it('5. logs nothing when there are no events', () => {
+  const events = [];
+  const action = makeAction();
+  logger(events, action);
+  expect(console.printHistory()).toMatchSnapshot();
+});
+
+it('6. logs events correctly even if console.group is undefined (RN)', () => {
+  console.group = undefined;
+  console.groupEnd = undefined;
+
+  const events = [
+    { hitType: 'pageview', page: '/' },
+    { hitType: 'pageview', page: '/home' },
+  ];
+
+  const action = makeAction();
+  logger(events, action);
+  expect(console.printHistory()).toMatchSnapshot();
+});
+
+describe('getTimestamp(date)', () => {
+  it('returns a timestamp', () => {
+    expect(getTimestamp(1489105897606)).toEqual('19:31:37.606');
+  });
+});

diff --git a/packages/segment/src/__tests__/segment.test.js b/packages/segment/src/__tests__/segment.test.js
new file mode 100644
index 0000000..63957c4
--- /dev/null
+++ b/packages/segment/src/__tests__/segment.test.js
@@ -0,0 +1,45 @@
+import { Segment } from '../';
+
+window.analytics = {
+  identify: jest.fn(),
+  group: jest.fn(),
+  page: jest.fn(),
+  track: jest.fn(),
+  alias: jest.fn(),
+};
+const target = Segment();
+
+describe('Target: Segment.io', () => {
+  it('does not call any service when hitType is undefined', () => {
+    const events = [
+      {
+        hitType: undefined,
+      },
+    ];
+    target(events);
+    Object.keys(window.analytics).forEach(key => {
+      expect(window.analytics[key]).not.toHaveBeenCalled();
+    });
+  });
+
+  it('calls track service when hitType is event', () => {
+    const events = [
+      {
+        hitType: 'event',
+        eventAction: 'random event action',
+      },
+    ];
+    target(events);
+    expect(window.analytics.track).toHaveBeenCalledWith(
+      events[0].eventAction,
+      events[0]
+    );
+  });
+});
+
+describe('When Segment is not defined', () => {
+  it('should throw an error informing the user.', () => {
+    window.analytics = undefined;
+    expect(() => target()).toThrowErrorMatchingSnapshot();
+  });
+});

